using SkiaSharp;
using Core;
try
{
    Console.WriteLine($"Expected native minimum: {SkiaSharpVersion.NativeMinimum}");
    Console.WriteLine($"Actual native version: {SkiaSharpVersion.Native}");
    Console.WriteLine($"Compatible: {SkiaSharpVersion.CheckNativeLibraryCompatible(false)}");
    var result = CoreHelper.GetSkiaInfo();
    Console.WriteLine(result);
}
catch (Exception ex)
{
    Console.Error.WriteLine($"ERROR: {ex.GetType().Name}: {ex.Message}");
    if (ex.InnerException != null)
        Console.Error.WriteLine($"INNER: {ex.InnerException.GetType().Name}: {ex.InnerException.Message}");
    Environment.ExitCode = 1;
}
